                clauses.append(f"is at an elevation of {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                clauses.append(f"has an IATA location identifier of {obj}")
            elif predicate == "nativeName":
                clauses.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                clauses.append(f"has a leader party of {obj}")
            elif predicate == "runwayName":
                clauses.append(f"is {obj}")
            elif predicate == "runwaySurfaceType":
                clauses.append(f"has a runway with {obj} surface")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                clauses.append(f"is at an elevation of {obj} metres above sea level")
            elif predicate == "officialLanguage":
                clauses.append(f"has {obj} as its official language")
            elif predicate == "demonym":
                clauses.append(f"whose people are called {obj}")
            else:
                # Handle other predicates with more natural phrasing
                normalized_pred = predicate.replace('1stRunway', 'first runway').replace('2ndRunway', 'second runway').replace('3rdRunway', 'third runway').replace('4thRunway', 'fourth runway').replace('5thRunway', 'fifth runway').replace('Length', ' length').replace('SurfaceType', ' surface type').replace('AboveTheSeaLevel', ' above sea level').replace('LocationIdentifier', ' identifier').replace('Iata', 'IATA').replace('Icao', 'ICAO').replace('InFeet', ' in feet').replace('InMetres', ' in metres')
                if "runway" in predicate or "elevation" in predicate or "length" in predicate:
                    if "runwayName" in predicate:
                        clauses.append(f"is {obj}")
                    else:
                        clauses.append(f"has {normalized_pred} of {obj}")
                else:
                    clauses.append(f"has a {normalized_pred} of {obj}")

    # Join all clauses with appropriate connectors
    if clauses:
        sentence += " " + ", ".join(clauses)

    return sentence + "."

